// Decision history synthesizer: ~420 decisions over ~30 days, generated by WALKING
// THE REAL SEEDED GRAPHS (walk.ts) with band-targeted inputs — every trace is the
// node path the deployed graph version actually takes for that input, every
// disposition is the flow's bound policy applied to the terminal record, and every
// model output is the registry model evaluated over the record. Volume follows a
// day/night rhythm, environments and versions follow each flow's deployments
// (challenger arms included), failures truncate at a named node with a believable
// provider error, and a few runs are left suspended at their manual-review node.

import type { Decision, Disposition, Environment, Flow, Model, Policy, NodeRecord } from '$lib/api';
import { walkGraph, applyPolicySpec } from '../walk';
import { now } from './base';

