// Traffic mix: one 30-slot rotation ≈ the fleet's relative volumes (fraud and AML
// dominate, onboarding/servicing flows trickle). 14 rotations ⇒ 420 decisions.
const PATTERN = [
  'card-fraud',
  'aml-screening',
  'credit-decision',
  'card-fraud',
  'dispute-triage',
  'aml-screening',
  'kyc-onboarding',
  'card-fraud',
  'credit-decision',
  'payout-risk',
  'aml-screening',
  'card-fraud',
  'merchant-onboarding',
  'credit-decision',
  'aml-screening',
  'card-fraud',
  'dispute-triage',
  'kyc-onboarding',
  'payout-risk',
  'collections-hardship',
  'card-fraud',
  'aml-screening',
  'credit-decision',
  'claim-triage',
  'card-fraud',
  'aml-screening',
  'limit-increase',
  'dispute-triage',
  'kyc-onboarding',
  'card-fraud'
];
const ROTATIONS = 14;

// Per-node latency contributions (ms): connectors and LLM calls dominate, pure
// compute is cheap — so a flow's duration tracks the depth and shape of the graph
// it actually walked.
const NODE_COST = new Map<string, number>([
  ['input', 2],
  ['assignment', 3],
  ['rule', 3],
  ['scorecard', 4],
  ['decision_table', 4],
  ['2d_matrix', 4],
  ['code', 5],
  ['reason', 2],
  ['split', 2],
  ['output', 3],
  ['predict', 12],
  ['connect', 85],
  ['ai', 190],
  ['manual_review', 6]
]);

function traceDuration(nodes: NodeRecord[], jitter: number): number {
  const base = nodes.reduce((sum, n) => sum + (NODE_COST.get(n.type) ?? 3), 0);
  return base + jitter;
}

function deployedVersion(flow: Flow, env: Environment, challenger: boolean): number {
  const dep = new Map(Object.entries(flow.deployments ?? {})).get(env);
  if (!dep) throw new Error(`seed: ${flow.slug} has no ${env} deployment`);
  if (challenger) {
    if (!dep.challenger_version) throw new Error(`seed: ${flow.slug} has no ${env} challenger`);
    return dep.challenger_version;
  }
  return dep.version;
}

// seedDecisions walks the deployed graphs with the profiles above. Throws (fails
// the whole seed, loudly) if any crafted input fails to complete its walk — a seed
// bug, never something to paper over.
export function seedDecisions(flows: Flow[], models: Model[], policies: Policy[]): Decision[] {
  const flowsBySlug = new Map(flows.map((f) => [f.slug, f]));
  const policyBySlug = new Map(policies.map((p) => [p.flow_slug, p]));
  const counters = new Map<string, number>();
  const out: Decision[] = [];
  let hoursAgo = 1.2;

  const total = PATTERN.length * ROTATIONS;
  for (let i = 1; i <= total; i++) {
    const slug = PATTERN[(i - 1) % PATTERN.length];
    const profile = PROFILES.find((p) => p.slug === slug);
    const flow = flowsBySlug.get(slug);
    if (!profile || !flow) throw new Error(`seed: unknown flow ${slug}`);
    const j = counters.get(slug) ?? 0;
    counters.set(slug, j + 1);

    const env = profile.envs[j % profile.envs.length];
    const challenger =
      profile.challenger !== undefined &&
      env === profile.challenger.env &&
      j % profile.challenger.every === 0;
    const version = deployedVersion(flow, env, challenger);
    const graph = flow.versions.find((v) => v.version === version)?.graph;
    if (!graph) throw new Error(`seed: ${slug} v${version} missing`);

    const suspend = profile.suspendAt?.includes(j) ?? false;
    const fail = !suspend && (profile.fail?.at.includes(j) ?? false);
    const band = suspend ? 'refer' : profile.dispositions[j % profile.dispositions.length];
    const input = profile.input(j, band);
    const run = walkGraph(graph, input, models);
    if (run.status !== 'completed') {
      throw new Error(`seed: ${slug} v${version} j=${j} did not complete: ${run.error}`);
    }

    const startedMs = now.getTime() - hoursAgo * 3600_000;
    const hourOfDay = new Date(startedMs).getHours();
    const night = hourOfDay < 7 || hourOfDay >= 21;
    hoursAgo += night ? 3.4 + (i % 5) * 0.8 : 0.75 + (i % 4) * 0.35;
    const startedAt = new Date(startedMs).toISOString();

    const decision: Decision = {
      decision_id: `dec_${i}`,
      flow_id: flow.flow_id,
      slug,
      version,
      environment: env,
      variant: challenger ? 'challenger' : 'champion',
      status: 'completed',
      data: run.data,
      output: run.output,
      reason_codes: run.reasonCodes,
      nodes: run.nodes,
      started_at: startedAt
    };

    if (fail && profile.fail) {
      // A believable mid-run infrastructure failure: the trace ends where the
      // named node would have run, the request payload is all that was recorded.
      const idx = run.nodes.findIndex((n) => n.node_id === profile.fail?.node);
      if (idx < 0) throw new Error(`seed: fail node ${profile.fail.node} not on ${slug}'s path`);
      const walked = run.nodes.slice(0, idx);
      const duration = traceDuration(walked, 800 + (i % 5) * 40);
      decision.status = 'failed';
      decision.data = input;
      decision.output = {};
      decision.reason_codes = [];
      decision.nodes = walked;
      decision.error = profile.fail.error;
      decision.ended_at = new Date(startedMs + duration).toISOString();
      decision.duration_ms = duration;
    } else if (suspend) {
      // Paused at the durable human task: the trace ends AT the manual-review
      // node, no terminal output or disposition yet — Resume completes it.
      const idx = run.nodes.findIndex((n) => n.type === 'manual_review');
      const reviewNode = run.nodes.at(idx);
      if (idx < 0 || !reviewNode) {
        throw new Error(`seed: no manual_review on ${slug}'s refer path`);
      }
      const walked = [...run.nodes.slice(0, idx), { ...reviewNode, output: { suspended: true } }];
      decision.status = 'suspended';
      decision.output = {};
      decision.nodes = walked;
      decision.policy_id = policyBySlug.get(slug)?.policy_id;
    } else {
      const policy = policyBySlug.get(slug);
      const spec = policy?.versions.find((v) => v.version === policy.latest)?.spec;
      if (!policy || !spec) throw new Error(`seed: no policy bound to ${slug}`);
      const banded = applyPolicySpec(spec, run.data, run.reasonCodes);
      const duration = traceDuration(run.nodes, (i % 6) * 7 + (i % 11));
      decision.disposition = banded.disposition;
      decision.disposition_reason = banded.reason;
      decision.policy_id = policy.policy_id;
      decision.policy_version = policy.latest;
      decision.ended_at = new Date(startedMs + duration).toISOString();
      decision.duration_ms = duration;
    }

    out.push(decision);
  }
  return out;
}
